INSERT INTO public.program_days (program_id, program_slug, day_number, day_title, title, content_text, estimated_minutes, cards)
VALUES (
  'a6e680d7-75d6-41e4-9434-200224d19393', 'age_reversal', 1,
  'Beginning the Rejuvenation Journey', 'Day 1 - Beginning the Rejuvenation Journey', '', 8,
  '[{"type":"intro","dayNumber":1,"dayTitle":"Beginning the Rejuvenation Journey","goal":"Start activating the body''s natural rejuvenation process by improving circulation, stimulating facial\nmuscles, and calming the nervous system.\nToday is about starting gently and building consistency.\nThese simple actions begin supporting:\n- hormone balance\n- skin elasticity\n- cellular repair\n- emotional calm","estimatedMinutes":8},{"type":"lesson","title":"Rejuvenation focus","paragraphs":["Start activating the body''s natural rejuvenation process by improving circulation, stimulating facial","muscles, and calming the nervous system.","Today is about starting gently and building consistency.","These simple actions begin supporting:","hormone balance","skin elasticity","cellular repair","emotional calm"],"highlight":"Start activating the body''s natural rejuvenation process by improving circulation, stimulating facial"},{"type":"action_step","stepNumber":1,"title":"Walking (circulation Activation)","duration":"20 minutes","instructions":["Take a 20-minute relaxed walk at any time during the day.","How to do it:","Walk at a comfortable pace.","Keep your posture upright.","Breathe naturally and stay relaxed.","Purpose:","improves blood circulation supports cellular energy production reduces physical tension"],"whyThisWorks":"Walking improves circulation and supports the recovery systems that keep skin and muscles supplied with oxygen and nutrients."},{"type":"exercise_routine","title":"Face Exercise (cheek Lift)","totalDuration":"4 minutes","exercises":[{"name":"Cheek Lift","instructions":["Sit comfortably with your back straight.","Smile as wide as possible.","Place your fingers lightly on the top of your cheeks.","Gently lift the cheek muscles upward toward the eyes.","Hold for 10 seconds.","Repeat 10 times."]}]},{"type":"calm_trigger","context":"Use CALM to lower stress, settle the nervous system, and reinforce the recovery signal for the body."},{"type":"action_step","stepNumber":4,"title":"Sleep Preparation","duration":"30 minutes","instructions":["Tonight aim to sleep before 11 PM.","Before sleeping:","Turn off screens 30 minutes before bed.","Allow your body and mind to relax.","Go to bed at a consistent time.","Purpose:","supports growth hormone release improves skin repair helps regulate female hormones"],"whyThisWorks":"Consistent sleep supports hormone balance, skin repair, and overnight recovery."},{"type":"close","message":"Day 1 is complete.","secondaryMessage":"Start activating the body''s natural rejuvenation process by improving circulation, stimulating facial\nmuscles, and calming the nervous system.\nToday is about starting gently and building consistency.\nThese simple actions begin supporting:\n- hormone balance\n- skin elasticity\n- cellular repair\n- emotional calm"}]'::jsonb
)
ON CONFLICT (program_slug, day_number) DO UPDATE SET
  cards = EXCLUDED.cards,
  day_title = EXCLUDED.day_title,
  estimated_minutes = EXCLUDED.estimated_minutes,
  updated_at = NOW();

INSERT INTO public.program_days (program_id, program_slug, day_number, day_title, title, content_text, estimated_minutes, cards)
VALUES (
  'a6e680d7-75d6-41e4-9434-200224d19393', 'age_reversal', 2,
  'Activating Facial Circulation', 'Day 2 - Activating Facial Circulation', '', 8,
  '[{"type":"intro","dayNumber":2,"dayTitle":"Activating Facial Circulation","goal":"Improve blood circulation in the face and body while continuing to calm the nervous system and\nmaintain healthy sleep habits.\nBetter circulation helps deliver oxygen and nutrients to the skin and muscles, supporting:\n- skin glow\n- facial muscle activation\n- cellular repair\n- hormone balance\n\nConsistency with small daily actions will gradually support natural age reversal.","estimatedMinutes":8},{"type":"lesson","title":"Rejuvenation focus","paragraphs":["Improve blood circulation in the face and body while continuing to calm the nervous system and","maintain healthy sleep habits.","Better circulation helps deliver oxygen and nutrients to the skin and muscles, supporting:","skin glow","facial muscle activation","cellular repair","hormone balance","Consistency with small daily actions will gradually support natural age reversal."],"highlight":"Improve blood circulation in the face and body while continuing to calm the nervous system and"},{"type":"action_step","stepNumber":1,"title":"Walking (circulation Boost)","duration":"20 minutes","instructions":["Take a 20-minute relaxed walk.","How to do it:","Walk at a comfortable pace.","Keep your shoulders relaxed.","Maintain steady breathing.","Purpose:","improves circulation throughout the body supports mitochondrial energy reduces physical tension"],"whyThisWorks":"Walking improves circulation and supports the recovery systems that keep skin and muscles supplied with oxygen and nutrients."},{"type":"exercise_routine","title":"Face Exercise (jawline Lift)","totalDuration":"4 minutes","exercises":[{"name":"Jawline Lift","instructions":["Sit or stand with your back straight.","Tilt your head slightly upward.","Look toward the ceiling.","Pucker your lips as if you are kissing the ceiling.","Hold for 5–10 seconds.","Repeat 10–12 times."]}]},{"type":"calm_trigger","context":"Use CALM to lower stress, settle the nervous system, and reinforce the recovery signal for the body."},{"type":"action_step","stepNumber":4,"title":"Sleep Preparation","duration":"30 minutes","instructions":["Tonight aim to sleep before 11 PM.","Before sleeping:","Turn off screens 30 minutes before bed.","Relax the body and mind.","Maintain a consistent sleep time.","Purpose:","supports hormone recovery improves skin repair enhances overall energy"],"whyThisWorks":"Consistent sleep supports hormone balance, skin repair, and overnight recovery."},{"type":"close","message":"Day 2 is complete.","secondaryMessage":"Improve blood circulation in the face and body while continuing to calm the nervous system and\nmaintain healthy sleep habits.\nBetter circulation helps deliver oxygen and nutrients to the skin and muscles, supporting:\n- skin glow\n- facial muscle activation\n- cellular repair\n- hormone balance\n\nConsistency with small daily actions will gradually support natural age reversal."}]'::jsonb
)
ON CONFLICT (program_slug, day_number) DO UPDATE SET
  cards = EXCLUDED.cards,
  day_title = EXCLUDED.day_title,
