INSERT INTO public.program_days (program_id, program_slug, day_number, day_title, title, content_text, estimated_minutes, cards)
VALUES (
  'a6e680d7-75d6-41e4-9434-200224d19393', 'age_reversal', 3,
  'Strengthening Facial Muscles', 'Day 3 - Strengthening Facial Muscles', '', 8,
  '[{"type":"intro","dayNumber":3,"dayTitle":"Strengthening Facial Muscles","goal":"Increase facial muscle activation and circulation while continuing daily movement and maintaining\nhealthy sleep habits.\nStronger facial muscles help support:\n- skin firmness\n- improved blood flow to the face\n- better muscle tone around cheeks and jawline\nConsistency in facial exercises gradually helps the face look more lifted and energized.","estimatedMinutes":8},{"type":"lesson","title":"Rejuvenation focus","paragraphs":["Increase facial muscle activation and circulation while continuing daily movement and maintaining","healthy sleep habits.","Stronger facial muscles help support:","skin firmness","improved blood flow to the face","better muscle tone around cheeks and jawline","Consistency in facial exercises gradually helps the face look more lifted and energized."],"highlight":"Increase facial muscle activation and circulation while continuing daily movement and maintaining"},{"type":"action_step","stepNumber":1,"title":"Walking (body Circulation)","duration":"20 minutes","instructions":["Take a 20-minute relaxed walk.","How to do it:","Walk at a comfortable pace.","Keep your back straight and shoulders relaxed.","Breathe naturally while walking.","Purpose:","improves circulation throughout the body supports cellular energy production reduces tension in the body"],"whyThisWorks":"Walking improves circulation and supports the recovery systems that keep skin and muscles supplied with oxygen and nutrients."},{"type":"exercise_routine","title":"Face Exercise (cheek Lift)","totalDuration":"5 minutes","exercises":[{"name":"Cheek Lift","instructions":["Sit comfortably with your back straight.","Smile as wide as possible.","Place your fingers gently on the top of your cheeks.","Lift the cheek muscles upward toward the eyes.","Hold for 10 seconds."],"reps":"10 repetitions per set - 2 sets total","rest":"2 sets"}]},{"type":"calm_trigger","context":"Use CALM to lower stress, settle the nervous system, and reinforce the recovery signal for the body."},{"type":"action_step","stepNumber":4,"title":"Sleep Preparation","duration":"30 minutes","instructions":["Tonight aim to sleep before 11 PM.","Before sleeping:","Turn off screens 30 minutes before bed.","Relax the body and mind.","Go to bed at a consistent time.","Purpose:","supports hormone recovery improves skin repair promotes deep sleep"],"whyThisWorks":"Consistent sleep supports hormone balance, skin repair, and overnight recovery."},{"type":"close","message":"Day 3 is complete.","secondaryMessage":"Increase facial muscle activation and circulation while continuing daily movement and maintaining\nhealthy sleep habits.\nStronger facial muscles help support:\n- skin firmness\n- improved blood flow to the face\n- better muscle tone around cheeks and jawline\nConsistency in facial exercises gradually helps the face look more lifted and energized."}]'::jsonb
)
