INSERT INTO public.program_days (program_id, program_slug, day_number, day_title, title, content_text, estimated_minutes, cards)
VALUES (
  'a6e680d7-75d6-41e4-9434-200224d19393', 'age_reversal', 4,
  'Improving Facial Tone', 'Day 4 - Improving Facial Tone', '', 8,
  '[{"type":"intro","dayNumber":4,"dayTitle":"Improving Facial Tone","goal":"Further activate facial muscles and circulation while maintaining body movement and calmness.\nRegular facial muscle activation helps support:\n- improved skin firmness\n- better blood flow to facial tissues\n- stronger cheek and jaw muscles\n- gradual facial toning\nConsistency is key. Small daily improvements help the face and body adapt naturally.","estimatedMinutes":8},{"type":"lesson","title":"Rejuvenation focus","paragraphs":["Further activate facial muscles and circulation while maintaining body movement and calmness.","Regular facial muscle activation helps support:","improved skin firmness","better blood flow to facial tissues","stronger cheek and jaw muscles","gradual facial toning","Consistency is key. Small daily improvements help the face and body adapt naturally."],"highlight":"Further activate facial muscles and circulation while maintaining body movement and calmness."},{"type":"action_step","stepNumber":1,"title":"Walking (circulation Support)","duration":"20 minutes","instructions":["Take a 20-minute relaxed walk.","How to do it:","Walk at a comfortable pace.","Keep your posture upright.","Relax your shoulders while walking.","Purpose:","improves blood circulation supports cellular energy helps reduce body tension"],"whyThisWorks":"Walking improves circulation and supports the recovery systems that keep skin and muscles supplied with oxygen and nutrients."},{"type":"exercise_routine","title":"Face Exercise (jawline Lift)","totalDuration":"6 minutes","exercises":[{"name":"Jawline Lift","instructions":["Stand or sit with your back straight.","Tilt your head slightly upward.","Look toward the ceiling.","Pucker your lips as if you are kissing the ceiling.","Hold for 10 seconds."],"reps":"10 repetitions per set - 3 sets total","rest":"3 sets"}]},{"type":"calm_trigger","context":"Use CALM to lower stress, settle the nervous system, and reinforce the recovery signal for the body."},{"type":"action_step","stepNumber":4,"title":"Sleep Preparation","duration":"30 minutes","instructions":["Tonight aim to sleep before 11 PM.","Before sleeping:","Turn off screens 30 minutes before bed.","Allow your body to relax.","Maintain a consistent sleep time.","Purpose:","supports hormone recovery improves skin repair promotes deeper sleep"],"whyThisWorks":"Consistent sleep supports hormone balance, skin repair, and overnight recovery."},{"type":"close","message":"Day 4 is complete.","secondaryMessage":"Further activate facial muscles and circulation while maintaining body movement and calmness.\nRegular facial muscle activation helps support:\n- improved skin firmness\n- better blood flow to facial tissues\n- stronger cheek and jaw muscles\n- gradual facial toning\nConsistency is key. Small daily improvements help the face and body adapt naturally."}]'::jsonb
)
