INSERT INTO public.program_days (program_id, program_slug, day_number, day_title, title, content_text, estimated_minutes, cards)
VALUES (
  'a6e680d7-75d6-41e4-9434-200224d19393', 'age_reversal', 5,
  'Increasing Facial Muscle Activation', 'Day 5 - Increasing Facial Muscle Activation', '', 8,
  '[{"type":"intro","dayNumber":5,"dayTitle":"Increasing Facial Muscle Activation","goal":"Further strengthen the facial muscles and improve circulation by increasing the exercise volume\nwhile maintaining daily movement and calmness.\nConsistent facial activation supports:\n- improved skin firmness\n- better facial muscle tone\n\n- increased blood circulation in the face\n- gradual natural lifting of facial features\nSmall daily improvements help build long-term facial strength and vitality.","estimatedMinutes":8},{"type":"lesson","title":"Rejuvenation focus","paragraphs":["Further strengthen the facial muscles and improve circulation by increasing the exercise volume","while maintaining daily movement and calmness.","Consistent facial activation supports:","improved skin firmness","better facial muscle tone","increased blood circulation in the face","gradual natural lifting of facial features","Small daily improvements help build long-term facial strength and vitality."],"highlight":"Further strengthen the facial muscles and improve circulation by increasing the exercise volume"},{"type":"action_step","stepNumber":1,"title":"Walking (body Circulation)","duration":"20 minutes","instructions":["Take a 20-minute relaxed walk.","How to do it:","Walk at a comfortable pace.","Keep your posture upright.","Let your arms swing naturally while walking.","Purpose:","improves circulation throughout the body supports cellular energy production helps reduce physical tension"],"whyThisWorks":"Walking improves circulation and supports the recovery systems that keep skin and muscles supplied with oxygen and nutrients."},{"type":"exercise_routine","title":"Face Exercise (cheek Lift)","totalDuration":"8 minutes","exercises":[{"name":"Cheek Lift","instructions":["Sit comfortably with your back straight.","Smile as wide as possible.","Place your fingers lightly on the top of your cheeks.","Gently lift the cheek muscles upward toward the eyes.","Hold for 10 seconds."],"reps":"12 repetitions per set - 4 sets total","rest":"4 sets"}]},{"type":"calm_trigger","context":"Use CALM to lower stress, settle the nervous system, and reinforce the recovery signal for the body."},{"type":"action_step","stepNumber":4,"title":"Sleep Preparation","duration":"30 minutes","instructions":["Tonight aim to sleep before 11 PM.","Before sleeping:","Turn off screens 30 minutes before bed.","Allow your body to relax.","Go to bed at a consistent time.","Purpose:","supports hormone recovery improves skin repair promotes deeper sleep"],"whyThisWorks":"Consistent sleep supports hormone balance, skin repair, and overnight recovery."},{"type":"close","message":"Day 5 is complete.","secondaryMessage":"Further strengthen the facial muscles and improve circulation by increasing the exercise volume\nwhile maintaining daily movement and calmness.\nConsistent facial activation supports:\n- improved skin firmness\n- better facial muscle tone\n\n- increased blood circulation in the face\n- gradual natural lifting of facial features\nSmall daily improvements help build long-term facial strength and vitality."}]'::jsonb
)
