INSERT INTO public.program_days (program_id, program_slug, day_number, day_title, title, content_text, estimated_minutes, cards)
VALUES (
  'a6e680d7-75d6-41e4-9434-200224d19393', 'age_reversal', 7,
  'Activating Multiple Facial Muscles', 'Day 7 - Activating Multiple Facial Muscles', '', 8,
  '[{"type":"intro","dayNumber":7,"dayTitle":"Activating Multiple Facial Muscles","goal":"Strengthen multiple facial muscle groups while maintaining daily movement, calmness, and\nconsistent sleep habits.\nTraining different facial muscles helps support:\n- better facial balance\n- improved circulation across the face\n- stronger cheek and jaw muscles\n- improved facial tone\nThis is the first step toward full facial muscle activation.","estimatedMinutes":8},{"type":"lesson","title":"Rejuvenation focus","paragraphs":["Strengthen multiple facial muscle groups while maintaining daily movement, calmness, and","consistent sleep habits.","Training different facial muscles helps support:","better facial balance","improved circulation across the face","stronger cheek and jaw muscles","improved facial tone","This is the first step toward full facial muscle activation."],"highlight":"Strengthen multiple facial muscle groups while maintaining daily movement, calmness, and"},{"type":"action_step","stepNumber":1,"title":"Walking (daily Circulation)","duration":"20 minutes","instructions":["Take a 20-minute relaxed walk.","How to do it:","Walk at a comfortable pace.","Keep your posture upright.","Allow your arms to move naturally.","Purpose:","improves blood circulation supports energy production in cells reduces physical tension"],"whyThisWorks":"Walking improves circulation and supports the recovery systems that keep skin and muscles supplied with oxygen and nutrients."},{"type":"exercise_routine","title":"Face Exercise 1 (cheek Lift)","totalDuration":"9 minutes","exercises":[{"name":"Cheek Lift","instructions":["Sit comfortably with your back straight.","Smile as wide as possible.","Place your fingers gently on the top of your cheeks.","Lift the cheek muscles upward toward the eyes.","Hold for 10 seconds."],"reps":"12 repetitions per set - 5 sets total","rest":"5 sets"}]},{"type":"exercise_routine","title":"Face Exercise 2 (jawline Lift)","totalDuration":"5-8 minutes","exercises":[{"name":"Jawline Lift","instructions":["Sit or stand with your back straight.","Tilt your head slightly upward.","Look toward the ceiling.","Pucker your lips as if kissing the ceiling.","Hold for 10 seconds."],"reps":"10 repetitions per set","rest":"3 sets"}]},{"type":"calm_trigger","context":"Use CALM to lower stress, settle the nervous system, and reinforce the recovery signal for the body."},{"type":"action_step","stepNumber":5,"title":"Sleep Preparation","duration":"30 minutes","instructions":["Tonight aim to sleep before 11 PM.","Before sleeping:","Turn off screens 30 minutes before bed.","Allow the body to relax.","Maintain a consistent sleep schedule.","Purpose:","supports hormone recovery improves skin repair promotes deeper sleep"],"whyThisWorks":"Consistent sleep supports hormone balance, skin repair, and overnight recovery."},{"type":"close","message":"Day 7 is complete.","secondaryMessage":"Strengthen multiple facial muscle groups while maintaining daily movement, calmness, and\nconsistent sleep habits.\nTraining different facial muscles helps support:\n- better facial balance\n- improved circulation across the face\n- stronger cheek and jaw muscles\n- improved facial tone\nThis is the first step toward full facial muscle activation."}]'::jsonb
)
