INSERT INTO public.program_days (program_id, program_slug, day_number, day_title, title, content_text, estimated_minutes, cards)
VALUES (
  'a6e680d7-75d6-41e4-9434-200224d19393', 'age_reversal', 9,
  'Activating Eye Area Muscles', 'Day 9 - Activating Eye Area Muscles', '', 8,
  '[{"type":"intro","dayNumber":9,"dayTitle":"Activating Eye Area Muscles","goal":"Strengthen the muscles around the eyes while maintaining body circulation, calmness, and\nconsistent sleep habits.\nThe eye area is one of the first places where aging appears. Strengthening these muscles helps\nsupport:\n- improved circulation around the eyes\n- reduced tension in the eye area\n- stronger facial muscle tone\n- better overall facial balance\nDaily consistency helps the face gradually appear more refreshed and energized.","estimatedMinutes":8},{"type":"lesson","title":"Rejuvenation focus","paragraphs":["Strengthen the muscles around the eyes while maintaining body circulation, calmness, and","consistent sleep habits.","The eye area is one of the first places where aging appears. Strengthening these muscles helps","support:","improved circulation around the eyes","reduced tension in the eye area","stronger facial muscle tone","better overall facial balance","Daily consistency helps the face gradually appear more refreshed and energized."],"highlight":"Strengthen the muscles around the eyes while maintaining body circulation, calmness, and"},{"type":"action_step","stepNumber":1,"title":"Walking (body Circulation)","duration":"20 minutes","instructions":["Take a 20-minute relaxed walk.","How to do it:","Walk at a comfortable pace.","Keep your posture upright.","Relax your shoulders while walking.","Purpose:","improves circulation throughout the body supports cellular energy production reduces body tension"],"whyThisWorks":"Walking improves circulation and supports the recovery systems that keep skin and muscles supplied with oxygen and nutrients."},{"type":"exercise_routine","title":"Face Exercise (eye Area Tightening)","totalDuration":"11 minutes","exercises":[{"name":"Eye Area Tightening","instructions":["Sit comfortably with your back straight.","Place your index fingers gently at the outer corners of your eyes.","Slightly squint your eyes while keeping the face relaxed.","Hold the position for 5–8 seconds.","Relax the eyes."],"reps":"10 repetitions per set - 7 sets total"}]},{"type":"calm_trigger","context":"Use CALM to lower stress, settle the nervous system, and reinforce the recovery signal for the body."},{"type":"action_step","stepNumber":4,"title":"Sleep Preparation","duration":"30 minutes","instructions":["Tonight aim to sleep before 11 PM.","Before sleeping:","Turn off screens 30 minutes before bed.","Allow the body to relax.","Maintain a consistent sleep schedule.","Purpose:","supports hormone recovery improves skin repair promotes deeper sleep"],"whyThisWorks":"Consistent sleep supports hormone balance, skin repair, and overnight recovery."},{"type":"close","message":"Day 9 is complete.","secondaryMessage":"Strengthen the muscles around the eyes while maintaining body circulation, calmness, and\nconsistent sleep habits.\nThe eye area is one of the first places where aging appears. Strengthening these muscles helps\nsupport:\n- improved circulation around the eyes\n- reduced tension in the eye area\n- stronger facial muscle tone\n- better overall facial balance\nDaily consistency helps the face gradually appear more refreshed and energized."}]'::jsonb
)
