INSERT INTO public.program_days (program_id, program_slug, day_number, day_title, title, content_text, estimated_minutes, cards)
VALUES (
  'a6e680d7-75d6-41e4-9434-200224d19393', 'age_reversal', 10,
  'Strengthening the Forehead Muscles', 'Day 10 - Strengthening the Forehead Muscles', '', 8,
  '[{"type":"intro","dayNumber":10,"dayTitle":"Strengthening the Forehead Muscles","goal":"Activate and strengthen the forehead muscles while continuing daily movement, calmness, and\nconsistent sleep habits.\nThe forehead is one of the most expressive parts of the face. Strengthening this area helps support:\n- improved forehead muscle tone\n- better circulation in the upper face\n- relaxation of facial tension\n- improved facial balance\nConsistent facial activation helps the face gradually become more toned and relaxed.","estimatedMinutes":8},{"type":"lesson","title":"Rejuvenation focus","paragraphs":["Activate and strengthen the forehead muscles while continuing daily movement, calmness, and","consistent sleep habits.","The forehead is one of the most expressive parts of the face. Strengthening this area helps support:","improved forehead muscle tone","better circulation in the upper face","relaxation of facial tension","improved facial balance","Consistent facial activation helps the face gradually become more toned and relaxed."],"highlight":"Activate and strengthen the forehead muscles while continuing daily movement, calmness, and"},{"type":"action_step","stepNumber":1,"title":"Walking (body Circulation)","duration":"20 minutes","instructions":["Take a 20-minute relaxed walk.","How to do it:","Walk at a comfortable pace.","Keep your back straight.","Relax your shoulders while walking.","Purpose:","improves circulation throughout the body supports cellular energy production reduces physical tension"],"whyThisWorks":"Walking improves circulation and supports the recovery systems that keep skin and muscles supplied with oxygen and nutrients."},{"type":"exercise_routine","title":"Face Exercise (forehead Smoothing)","totalDuration":"12 minutes","exercises":[{"name":"Forehead Smoothing","instructions":["Sit comfortably with your back straight.","Place both palms gently on your forehead.","Apply light pressure with your hands.","Try to raise your eyebrows while you